#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        long long f[N + 1];
        f[1] = 1;
        for (int i = 2; i <= N; i++) {
            f[i] = (f[i - 1] * i) % M;
        }
        for (int i = 0; i < Q; i++) {
            int r;
            scanf("%d", &r);
            long long ans = (f[N] * powMod(f[r], M - 2, M) * powMod(f[N - r], M - 2, M)) % M;
            printf("%lld\n", ans);
        }
    }
    return 0;
}

