import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int Q = sc.nextInt();
            long[] f = new long[N + 1];
            f[1] = 1;
            for (int i = 2; i <= N; i++) {
                f[i] = (f[i - 1] * i) % M;
            }
            for (int i = 0; i < Q; i++) {
                int r = sc.nextInt();
                long ans = (f[N] * powMod(f[r], M - 2, M) * powMod(f[N - r], M - 2, M)) % M;
                System.out.println(ans);
            }
        }
    }

    public static long powMod(long a, long b, long m) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % m;
            a = (a * a) % m;
            b >>= 1;
        }
        return res;
    }
}

